set_time_limit(120);
$base   = __DIR__;
$log    = [];
$hibak  = 0;

function ir($fajl, $tartalom, &$log, &$hibak) {
    $dir = dirname($fajl);
    if (!is_dir($dir)) {
        if (!mkdir($dir, 0755, true)) {
            $log[] = ['hiba', "Mappa nem hozható létre: $dir"];
            $hibak++;
            return false;
        }
    }
    if (file_put_contents($fajl, $tartalom) === false) {
        $log[] = ['hiba', "Fájl írás sikertelen: $fajl"];
        $hibak++;
        return false;
    }
    $log[] = ['ok', "Létrehozva: " . str_replace(__DIR__ . '/', '', $fajl)];
    return true;
}

// SABLON TARTALOM (base64)
$sablon_b64 = '';

$sablon = base64_decode($sablon_b64);

// 1. SABLON FÁJL LÉTREHOZÁSA
ir($base . '/includes/bojler-kerulet-sablon.php', $sablon, $log, $hibak);

// 2. 23 KERÜLETI INDEX.PHP LÉTREHOZÁSA
for ($i = 1; $i <= 23; $i++) {
    $tartalom = "<?php\n\$kid = {$i};\nrequire_once dirname(__DIR__) . '/includes/bojler-kerulet-sablon.php';\n";
    ir($base . '/bojler-szerelo-' . $i . '-kerulet/index.php', $tartalom, $log, $hibak);
}

